    const res = await client.query(
      "SELECT COUNT(*) AS n FROM information_schema.tables WHERE table_schema = 'public'"
    );
    const count = parseInt(res.rows[0].n, 10);
    return { count };
  } finally {
    await client.end();
  }
}

